// ═══════════════════════════════════════════
// HOOKS
// ═══════════════════════════════════════════
function useInView(opts = {}) {
  const ref = useRef(null);
  const [visible, setVisible] = useState(false);
  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const obs = new IntersectionObserver(
      ([e]) => { if (e.isIntersecting) setVisible(true); },
      { threshold: 0.12, ...opts }
    );
    obs.observe(el);
    return () => obs.disconnect();
  }, []);
  return [ref, visible];
}

function useScrollProgress(elementRef) {
  const [progress, setProgress] = useState(0);
  useEffect(() => {
    const handler = () => {
      if (!elementRef.current) return;
      const rect = elementRef.current.getBoundingClientRect();
      const vh = window.innerHeight;
      const p = Math.max(0, Math.min(1, 1 - (rect.top / vh)));
      setProgress(p);
    };
    window.addEventListener("scroll", handler, { passive: true });
    handler();
    return () => window.removeEventListener("scroll", handler);
  }, []);
  return progress;
}

// ═══════════════════════════════════════════
// REVEAL
// ═══════════════════════════════════════════
function Reveal({ children, delay = 0, className = "", style = {} }) {
  const [ref, v] = useInView();
  return (
    <div ref={ref} className={className} style={{
      opacity: v ? 1 : 0,
      transform: v ? "translateY(0)" : "translateY(50px)",
      transition: `all 0.9s cubic-bezier(0.22, 1, 0.36, 1) ${delay}s`,
      ...style,
    }}>
      {children}
    </div>
  );
}

// ═══════════════════════════════════════════
// GLOW TEXT — illuminates on hover
// ═══════════════════════════════════════════
function GlowText({ children, t, tag: Tag = "em" }) {
  const [hover, setHover] = useState(false);
  return (
    <Tag
      onMouseEnter={() => setHover(true)}
      onMouseLeave={() => setHover(false)}
      style={{
        fontWeight: 500, cursor: "default", position: "relative",
        transition: "all 0.5s cubic-bezier(0.22,1,0.36,1)",
        color: hover ? t.cognac : "inherit",
        textShadow: hover ? `0 0 30px ${t.ledGlow}, 0 0 60px ${t.ledGlow}50, 0 0 10px ${t.ledCore}` : "none",
        ...(hover ? {
          background: `linear-gradient(135deg, ${t.cognac}, ${t.gold})`,
          WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent",
          filter: `drop-shadow(0 0 18px ${t.ledGlow})`,
        } : {}),
      }}
    >
      {children}
      {/* Underline glow on hover */}
      <span style={{
        position: "absolute", bottom: -2, left: 0, right: 0, height: 2,
        background: `linear-gradient(90deg, transparent, ${t.ledCore}, transparent)`,
        borderRadius: 2,
        opacity: hover ? 1 : 0,
        transform: hover ? "scaleX(1)" : "scaleX(0)",
        transition: "all 0.5s cubic-bezier(0.22,1,0.36,1)",
        filter: "blur(1px)",
      }}/>
    </Tag>
  );
}

