// ═══════════════════════════════════════════
// LED OVAL MIRROR — with scroll-triggered light beams
// ═══════════════════════════════════════════
function LEDOvalMirror({ t, size = 320, children, intensity = 1, style: outerStyle = {}, showBeam = false, beamProgress = 0 }) {
  const w = size;
  const h = size * 1.35;
  // Beam angle derived from scroll progress
  const beamAngle = beamProgress * 360;

  return (
    <div style={{ position: "relative", width: w, height: h, ...outerStyle }}>
      {/* Outer halo pulse */}
      <div style={{
        position: "absolute", inset: -30, borderRadius: "50%",
        background: `radial-gradient(ellipse, ${t.ledGlow}, transparent 70%)`,
        animation: `ledPulse ${3 / intensity}s ease-in-out infinite`,
        opacity: 0.5 * intensity, pointerEvents: "none",
      }}/>
      {/* LED ring — animated conic gradient */}
      <div style={{
        position: "absolute", inset: -4, borderRadius: "50%",
        background: `conic-gradient(from var(--led-angle, 0deg), ${t.ledCore}, ${t.gold}80, transparent 30%, transparent 60%, ${t.gold}80, ${t.ledCore})`,
        animation: `ledSpin 4s linear infinite`,
        opacity: 0.9 * intensity, pointerEvents: "none", filter: "blur(1px)",
      }}/>
      {/* Inner LED ring */}
      <div style={{
        position: "absolute", inset: -2, borderRadius: "50%",
        border: `2px solid ${t.ledCore}`,
        boxShadow: `0 0 20px ${t.ledGlow}, 0 0 60px ${t.ledGlow}, inset 0 0 20px ${t.ledGlow}`,
        animation: `ledBreath 3s ease-in-out infinite`,
        pointerEvents: "none",
      }}/>
      {/* Scroll-triggered light beam sweeping across */}
      {showBeam && (
        <div style={{
          position: "absolute", inset: -6, borderRadius: "50%", pointerEvents: "none",
          overflow: "hidden",
        }}>
          <div style={{
            position: "absolute", inset: 0,
            background: `conic-gradient(from ${beamAngle}deg at 50% 50%, transparent 0deg, ${t.ledCore}80 8deg, ${t.ledCore} 15deg, ${t.ledCore}80 22deg, transparent 30deg, transparent 360deg)`,
            filter: "blur(3px)",
            transition: "none",
          }}/>
          {/* Second beam offset */}
          <div style={{
            position: "absolute", inset: 0,
            background: `conic-gradient(from ${beamAngle + 180}deg at 50% 50%, transparent 0deg, ${t.gold}50 5deg, ${t.gold}90 10deg, ${t.gold}50 15deg, transparent 20deg, transparent 360deg)`,
            filter: "blur(4px)",
          }}/>
        </div>
      )}
      {/* Mirror surface */}
      <div style={{
        position: "absolute", inset: 6, borderRadius: "50%",
        background: `linear-gradient(145deg, ${t.surface}F8, ${t.bgCard})`,
        overflow: "hidden", display: "flex", alignItems: "center", justifyContent: "center",
        boxShadow: `inset 0 2px 30px ${t.shadow}`,
      }}>
        {children}
      </div>
    </div>
  );
}

// ═══════════════════════════════════════════
// PHOTO FRAME — Oval with LED ring
// ═══════════════════════════════════════════
function PhotoOvalFrame({ t, src, size = 300, label, beamProgress = 0 }) {
  const w = size;
  const h = size * 1.3;
  const beamAngle = beamProgress * 360;
  const [hover, setHover] = useState(false);

  return (
    <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 16 }}>
      <div
        onMouseEnter={() => setHover(true)} onMouseLeave={() => setHover(false)}
        style={{
          position: "relative", width: w, height: h,
          transition: "transform 0.6s cubic-bezier(0.22,1,0.36,1)",
          transform: hover ? "scale(1.03)" : "scale(1)",
        }}
      >
        {/* Outer glow */}
        <div style={{
          position: "absolute", inset: -20, borderRadius: "50%",
          background: `radial-gradient(ellipse, ${t.ledGlow}, transparent 70%)`,
          opacity: hover ? 0.6 : 0.25,
          transition: "opacity 0.5s",
          animation: "ledPulse 4s ease-in-out infinite",
          pointerEvents: "none",
        }}/>
        {/* LED ring */}
        <div style={{
          position: "absolute", inset: -3, borderRadius: "50%",
          border: `2px solid ${t.ledCore}80`,
          boxShadow: hover
            ? `0 0 30px ${t.ledGlow}, 0 0 80px ${t.ledGlow}, inset 0 0 30px ${t.ledGlow}`
            : `0 0 15px ${t.ledGlow}60, 0 0 40px ${t.ledGlow}30`,
          transition: "box-shadow 0.5s",
          animation: "ledBreath 3s ease-in-out infinite",
          pointerEvents: "none",
        }}/>
        {/* Light beam on scroll */}
        <div style={{
          position: "absolute", inset: -5, borderRadius: "50%", pointerEvents: "none",
          overflow: "hidden", opacity: 0.7,
        }}>
          <div style={{
            position: "absolute", inset: 0,
            background: `conic-gradient(from ${beamAngle}deg at 50% 50%, transparent 0deg, ${t.ledCore}60 6deg, ${t.ledCore}CC 12deg, ${t.ledCore}60 18deg, transparent 24deg, transparent 360deg)`,
            filter: "blur(3px)",
          }}/>
        </div>
        {/* Photo clipped in oval */}
        <div style={{
          position: "absolute", inset: 5, borderRadius: "50%", overflow: "hidden",
          boxShadow: `inset 0 2px 30px ${t.shadow}`,
        }}>
          <img src={src} alt={label} style={{
            width: "100%", height: "100%", objectFit: "cover",
            filter: hover ? "brightness(1.08) contrast(1.02)" : "brightness(0.95)",
            transition: "filter 0.5s",
          }}/>
          {/* Glossy overlay */}
          <div style={{
            position: "absolute", inset: 0,
            background: `linear-gradient(160deg, rgba(255,255,255,0.1) 0%, transparent 50%, rgba(0,0,0,0.15) 100%)`,
            pointerEvents: "none",
          }}/>
        </div>
      </div>
      {label && (
        <span style={{
          fontFamily: "'Cormorant Garamond', serif", fontSize: 16, fontStyle: "italic",
          color: t.textMuted,
          textShadow: hover ? `0 0 15px ${t.ledGlow}50` : "none",
          transition: "text-shadow 0.5s",
        }}>{label}</span>
      )}
    </div>
  );
}

// ═══════════════════════════════════════════
// RECTANGULAR PHOTO FRAME with LED border
// ═══════════════════════════════════════════
function PhotoRectFrame({ t, src, label, ratio = "4/3", beamProgress = 0 }) {
  const [hover, setHover] = useState(false);
  const beamPos = (beamProgress * 200) - 50; // -50% to 150%

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
      <div
        onMouseEnter={() => setHover(true)} onMouseLeave={() => setHover(false)}
        style={{
          position: "relative", borderRadius: 20, overflow: "hidden",
          aspectRatio: ratio, cursor: "pointer",
          transition: "transform 0.5s cubic-bezier(0.22,1,0.36,1)",
          transform: hover ? "translateY(-6px)" : "",
        }}
      >
        {/* LED border */}
        <div style={{
          position: "absolute", inset: -1, borderRadius: 21,
          border: `2px solid ${t.ledCore}50`,
          boxShadow: hover
            ? `0 0 25px ${t.ledGlow}, 0 0 60px ${t.ledGlow}60, inset 0 0 20px ${t.ledGlow}30`
            : `0 0 10px ${t.ledGlow}30`,
          transition: "all 0.5s", pointerEvents: "none", zIndex: 2,
        }}/>
        {/* Sweeping light beam */}
        <div style={{
          position: "absolute", top: 0, left: 0, right: 0, height: "100%",
          pointerEvents: "none", zIndex: 3, overflow: "hidden", borderRadius: 20,
        }}>
          <div style={{
            position: "absolute", top: 0, width: "40%", height: "100%",
            left: `${beamPos}%`,
            background: `linear-gradient(90deg, transparent, ${t.ledCore}15, ${t.ledCore}25, ${t.ledCore}15, transparent)`,
            filter: "blur(8px)",
          }}/>
        </div>
        {/* Image */}
        <img src={src} alt={label} style={{
          width: "100%", height: "100%", objectFit: "cover",
          filter: hover ? "brightness(1.1)" : "brightness(0.92)",
          transition: "filter 0.5s",
        }}/>
        {/* Gradient overlay */}
        <div style={{
          position: "absolute", inset: 0, borderRadius: 20,
          background: "linear-gradient(transparent 50%, rgba(0,0,0,0.4) 100%)",
          pointerEvents: "none",
        }}/>
      </div>
      {label && (
        <span style={{
          fontFamily: "'DM Sans', sans-serif", fontSize: 13, fontWeight: 500,
          color: t.textMuted, textAlign: "center",
        }}>{label}</span>
      )}
    </div>
  );
}

// ═══════════════════════════════════════════
// FLOATING PARTICLES
// ═══════════════════════════════════════════
function FloatingParticles({ t, count = 25 }) {
  const particles = useRef(
    Array.from({ length: count }, () => ({
      x: Math.random() * 100, y: Math.random() * 100,
      size: 2 + Math.random() * 4,
      dur: 10 + Math.random() * 20,
      delay: Math.random() * -20,
      drift: 10 + Math.random() * 30,
    }))
  ).current;
  return (
    <div style={{ position: "absolute", inset: 0, overflow: "hidden", pointerEvents: "none" }}>
      {particles.map((p, i) => (
        <div key={i} style={{
          position: "absolute", left: `${p.x}%`, top: `${p.y}%`,
          width: p.size, height: p.size, borderRadius: "50%",
          background: `radial-gradient(circle, ${t.ledCore}, ${t.gold}40)`,
          boxShadow: `0 0 ${p.size * 3}px ${t.ledGlow}`,
          animation: `particleFloat ${p.dur}s ease-in-out ${p.delay}s infinite`,
          opacity: 0.4, "--drift": `${p.drift}px`,
        }}/>
      ))}
    </div>
  );
}

// ═══════════════════════════════════════════
// HERRINGBONE
// ═══════════════════════════════════════════
function Herringbone({ t, opacity = 0.04 }) {
  return (
    <svg style={{ position: "absolute", inset: 0, width: "100%", height: "100%", opacity, pointerEvents: "none" }}>
      <defs>
        <pattern id="hb" width="40" height="40" patternUnits="userSpaceOnUse">
          <line x1="0" y1="0" x2="20" y2="20" stroke={t.oakDark} strokeWidth="0.8"/>
          <line x1="20" y1="0" x2="40" y2="20" stroke={t.oakDark} strokeWidth="0.8"/>
          <line x1="0" y1="20" x2="20" y2="40" stroke={t.oakDark} strokeWidth="0.8"/>
          <line x1="20" y1="20" x2="40" y2="40" stroke={t.oakDark} strokeWidth="0.8"/>
        </pattern>
      </defs>
      <rect width="100%" height="100%" fill="url(#hb)"/>
    </svg>
  );
}

// ═══════════════════════════════════════════
// SIMPLE BUTTON (no magnetic effect)
// ═══════════════════════════════════════════
function Btn({ t, children, href, primary, style: s = {} }) {
  const [hover, setHover] = useState(false);
  const base = {
    fontFamily: "'DM Sans', sans-serif", fontSize: 14, fontWeight: 600,
    padding: "16px 40px", borderRadius: 50, textDecoration: "none", cursor: "pointer",
    letterSpacing: "0.06em", textTransform: "uppercase",
    display: "inline-flex", alignItems: "center", gap: 10,
    transition: "all 0.4s cubic-bezier(0.22,1,0.36,1)",
  };
  const prim = {
    color: "#FFF",
    background: `linear-gradient(135deg, ${t.cognac}, ${t.cognacLight})`,
    boxShadow: hover
      ? `0 12px 40px ${t.cognac}50, 0 0 25px ${t.ledGlow}25`
      : `0 8px 32px ${t.cognac}40`,
    transform: hover ? "translateY(-3px)" : "",
  };
  const sec = {
    color: t.text,
    background: `${t.surface}90`,
    border: `1.5px solid ${hover ? t.oak + "60" : t.oak + "30"}`,
    backdropFilter: "blur(10px)",
    boxShadow: hover ? `0 8px 30px ${t.shadow}, 0 0 20px ${t.ledGlow}15` : "none",
    transform: hover ? "translateY(-2px)" : "",
  };
  return (
    <a href={href} style={{ ...base, ...(primary ? prim : sec), ...s }}
      onMouseEnter={() => setHover(true)} onMouseLeave={() => setHover(false)}>
      {children}
    </a>
  );
}

// ═══════════════════════════════════════════
// SLATS
// ═══════════════════════════════════════════
function Slats({ t, count = 12, h = 160 }) {
  return (
    <div style={{ display: "flex", gap: 5, justifyContent: "center", height: h, alignItems: "flex-end" }}>
      {Array.from({ length: count }, (_, i) => {
        const ratio = Math.sin((i / (count - 1)) * Math.PI);
        return (
          <div key={i} style={{
            width: 3.5, height: h * (0.3 + ratio * 0.7), borderRadius: 2,
            background: `linear-gradient(180deg, ${t.oak}60, ${t.oak}15)`,
            animation: `slatGrow 1.2s cubic-bezier(0.22,1,0.36,1) ${i * 0.06}s both`,
          }}/>
        );
      })}
    </div>
  );
}

// ═══════════════════════════════════════════
// CURSOR GLOW
// ═══════════════════════════════════════════
function CursorGlow({ t }) {
  const [pos, setPos] = useState({ x: -200, y: -200 });
  const [vis, setVis] = useState(false);
  useEffect(() => {
    const mv = (e) => { setPos({ x: e.clientX, y: e.clientY }); setVis(true); };
    const lv = () => setVis(false);
    window.addEventListener("mousemove", mv);
    document.addEventListener("mouseleave", lv);
    return () => { window.removeEventListener("mousemove", mv); document.removeEventListener("mouseleave", lv); };
  }, []);
  return (
    <div style={{
      position: "fixed", pointerEvents: "none", zIndex: 9999,
      left: pos.x - 160, top: pos.y - 160,
      width: 320, height: 320, borderRadius: "50%",
      background: `radial-gradient(circle, ${t.ledGlow}15, transparent 70%)`,
      opacity: vis ? 1 : 0, transition: "opacity 0.3s", mixBlendMode: "screen",
    }}/>
  );
}

// ═══════════════════════════════════════════
// THEME TOGGLE
// ═══════════════════════════════════════════
function ThemeToggle({ dark, toggle, t }) {
  const [hover, setHover] = useState(false);
  return (
    <button onClick={toggle} aria-label="Toggle theme"
      onMouseEnter={() => setHover(true)} onMouseLeave={() => setHover(false)}
      style={{
        position: "fixed", bottom: 28, right: 28, zIndex: 100,
        width: 52, height: 52, borderRadius: "50%",
        background: t.surface, border: `1.5px solid ${t.oak}25`,
        boxShadow: hover
          ? `0 8px 30px ${t.shadow}, 0 0 50px ${t.ledGlow}50`
          : `0 4px 20px ${t.shadow}, 0 0 30px ${t.ledGlow}30`,
        display: "flex", alignItems: "center", justifyContent: "center",
        cursor: "pointer", color: t.gold,
        transition: "all 0.4s cubic-bezier(0.22,1,0.36,1)",
        transform: hover ? "scale(1.1) rotate(15deg)" : "scale(1)",
      }}
    >
      {dark ? I.sun : I.moon}
    </button>
  );
}

// ═══════════════════════════════════════════
// NAVBAR
// ═══════════════════════════════════════════
function Navbar({ t }) {
  const [scrolled, setScrolled] = useState(false);
  const [menuOpen, setMenuOpen] = useState(false);
  useEffect(() => {
    const fn = () => setScrolled(window.scrollY > 60);
    window.addEventListener("scroll", fn);
    return () => window.removeEventListener("scroll", fn);
  }, []);
  const links = ["Salon", "Prestations", "Galerie", "Avis", "Contact"];
  return (
    <>
      <nav style={{
        position: "fixed", zIndex: 50,
        top: scrolled ? 14 : 0, left: scrolled ? 16 : 0, right: scrolled ? 16 : 0,
        padding: scrolled ? "14px 28px" : "20px 40px",
        background: scrolled ? t.overlay : "transparent",
        backdropFilter: scrolled ? "blur(24px) saturate(180%)" : "none",
        borderRadius: scrolled ? 20 : 0,
        border: scrolled ? `1px solid ${t.oak}20` : "none",
        boxShadow: scrolled ? `0 4px 30px ${t.shadow}` : "none",
        transition: "all 0.5s cubic-bezier(0.22,1,0.36,1)",
        display: "flex", alignItems: "center", justifyContent: "space-between",
      }}>
        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
          <div style={{
            width: 38, height: 38, borderRadius: "50%",
            background: `linear-gradient(135deg, ${t.gold}, ${t.oak})`,
            display: "flex", alignItems: "center", justifyContent: "center",
            color: "#fff", boxShadow: `0 0 20px ${t.ledGlow}`,
          }}>
            <span style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: 15, fontWeight: 600 }}>H</span>
          </div>
          <span style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: 20, fontWeight: 600, color: t.text, letterSpacing: "0.02em" }}>
            L'Hair du Temps
          </span>
        </div>
        <div style={{ display: "flex", gap: 32, alignItems: "center" }} className="desktop-nav">
          {links.map(l => {
            const [hov, setHov] = useState(false);
            return (
              <a key={l} href={`#${l.toLowerCase()}`} style={{
                fontFamily: "'DM Sans', sans-serif", fontSize: 12.5, fontWeight: 500,
                color: hov ? t.cognac : t.textMuted, textDecoration: "none", letterSpacing: "0.1em",
                textTransform: "uppercase", cursor: "pointer", transition: "color 0.3s",
              }} onMouseEnter={() => setHov(true)} onMouseLeave={() => setHov(false)}>
                {l}
              </a>
            );
          })}
          <a href="#contact" style={{
            fontFamily: "'DM Sans', sans-serif", fontSize: 12.5, fontWeight: 600,
            color: "#fff", background: `linear-gradient(135deg, ${t.cognac}, ${t.cognacLight})`,
            padding: "10px 24px", borderRadius: 50, textDecoration: "none", cursor: "pointer",
            letterSpacing: "0.06em", textTransform: "uppercase",
            boxShadow: `0 4px 20px ${t.cognac}40, 0 0 15px ${t.ledGlow}20`,
            transition: "all 0.3s",
          }}>Réserver</a>
        </div>
        <button onClick={() => setMenuOpen(!menuOpen)} className="mobile-menu-btn"
          style={{ background: "none", border: "none", color: t.text, cursor: "pointer", padding: 4, display: "none" }}>
          {menuOpen ? I.close : I.menu}
        </button>
      </nav>
      {menuOpen && (
        <div style={{
          position: "fixed", inset: 0, zIndex: 49,
          background: t.overlay, backdropFilter: "blur(30px)",
          display: "flex", flexDirection: "column", alignItems: "center",
          justifyContent: "center", gap: 32,
        }}>
          {links.map(l => (
            <a key={l} href={`#${l.toLowerCase()}`} onClick={() => setMenuOpen(false)} style={{
              fontFamily: "'Cormorant Garamond', serif", fontSize: 28, fontWeight: 500,
              color: t.text, textDecoration: "none", cursor: "pointer",
            }}>{l}</a>
          ))}
        </div>
      )}
    </>
  );
}

