// ═══════════════════════════════════════════
// GALLERY — Immersive horizontal mood board
// ═══════════════════════════════════════════
function GalleryCard({ src, label, index, t, scrollP }) {
  const [hov, setHov] = useState(false);
  const [tilt, setTilt] = useState({ x: 0, y: 0 });
  const cardRef = useRef(null);
  const isOdd = index % 2 === 1;
  const rotation = ["-2deg", "1.5deg", "-1deg"][index] || "0deg";

  const handleMouseMove = (e) => {
    if (!cardRef.current) return;
    const rect = cardRef.current.getBoundingClientRect();
    const x = (e.clientX - rect.left) / rect.width - 0.5;
    const y = (e.clientY - rect.top) / rect.height - 0.5;
    setTilt({ x: y * -15, y: x * 15 });
  };

  const handleMouseLeave = () => {
    setHov(false);
    setTilt({ x: 0, y: 0 });
  };

  return (
    <div
      ref={cardRef}
      onMouseEnter={() => setHov(true)}
      onMouseMove={handleMouseMove}
      onMouseLeave={handleMouseLeave}
      style={{
        flex: "0 0 auto",
        width: index === 1 ? 380 : 300,
        marginTop: isOdd ? 0 : 60,
        transform: `rotate(${hov ? "0deg" : rotation}) perspective(800px) rotateX(${tilt.x}deg) rotateY(${tilt.y}deg) scale(${hov ? 1.05 : 1})`,
        transition: "transform 0.4s cubic-bezier(0.22,1,0.36,1), box-shadow 0.4s",
        cursor: "pointer",
        position: "relative",
      }}
    >
      <div style={{
        borderRadius: 20,
        overflow: "hidden",
        position: "relative",
        boxShadow: hov
          ? `0 30px 80px rgba(0,0,0,0.5), 0 0 40px ${THEMES.dark.ledGlow}30`
          : `0 15px 40px rgba(0,0,0,0.3)`,
        border: `1px solid ${hov ? THEMES.dark.gold + "40" : THEMES.dark.oak + "20"}`,
        transition: "box-shadow 0.4s, border-color 0.4s",
      }}>
        <img src={src} alt={label} style={{
          width: "100%",
          height: index === 1 ? 480 : 380,
          objectFit: "cover",
          display: "block",
          transition: "transform 0.6s cubic-bezier(0.22,1,0.36,1)",
          transform: hov ? "scale(1.08)" : "scale(1)",
        }}/>
        {/* LED glow overlay on hover */}
        <div style={{
          position: "absolute", inset: 0,
          background: `linear-gradient(180deg, transparent 40%, ${THEMES.dark.bg}dd 100%)`,
          opacity: hov ? 1 : 0.6,
          transition: "opacity 0.4s",
        }}/>
        {/* Animated LED border glow */}
        <div style={{
          position: "absolute", inset: -1,
          borderRadius: 20,
          background: `conic-gradient(from ${scrollP * 360}deg, ${THEMES.dark.gold}, transparent, ${THEMES.dark.cognac}, transparent, ${THEMES.dark.gold})`,
          opacity: hov ? 0.4 : 0,
          transition: "opacity 0.4s",
          zIndex: -1,
          padding: 2,
        }}/>
        {/* Label */}
        <div style={{
          position: "absolute", bottom: 0, left: 0, right: 0,
          padding: "24px 20px",
          transform: hov ? "translateY(0)" : "translateY(10px)",
          opacity: hov ? 1 : 0,
          transition: "all 0.4s cubic-bezier(0.22,1,0.36,1)",
        }}>
          <span style={{
            fontFamily: "'DM Sans', sans-serif",
            fontSize: 11, fontWeight: 600,
            color: THEMES.dark.gold,
            letterSpacing: "0.15em",
            textTransform: "uppercase",
          }}>{label}</span>
        </div>
      </div>
      {/* Reflection */}
      <div style={{
        height: 40,
        background: `linear-gradient(180deg, ${THEMES.dark.gold}08, transparent)`,
        borderRadius: "0 0 20px 20px",
        filter: "blur(8px)",
        transform: "scaleY(-0.3) translateY(-30px)",
        opacity: hov ? 0.5 : 0.15,
        transition: "opacity 0.4s",
      }}/>
    </div>
  );
}

function Gallery({ t }) {
  const sectionRef = useRef(null);
  const scrollP = useScrollProgress(sectionRef);
  const dark = t.bg === "#111010";
  const trackRef = useRef(null);
  const [isDragging, setIsDragging] = useState(false);
  const [startX, setStartX] = useState(0);
  const [scrollLeft, setScrollLeft] = useState(0);

  const photos = [
    { src: IMG_ACCUEIL, label: "Espace d'accueil" },
    { src: IMG_MIROIRS, label: "Postes de coiffage" },
    { src: IMG_STATIONS, label: "Ambiance lumineuse" },
  ];

  const handleMouseDown = (e) => {
    setIsDragging(true);
    setStartX(e.pageX - trackRef.current.offsetLeft);
    setScrollLeft(trackRef.current.scrollLeft);
  };
  const handleMouseUp = () => setIsDragging(false);
  const handleMouseMove = (e) => {
    if (!isDragging) return;
    e.preventDefault();
    const x = e.pageX - trackRef.current.offsetLeft;
    trackRef.current.scrollLeft = scrollLeft - (x - startX) * 1.5;
  };

  return (
    <section id="galerie" ref={sectionRef} style={{
      padding: "130px 0", position: "relative", overflow: "hidden",
      background: dark ? "#0B0A09" : "#1A1612",
    }}>
      <FloatingParticles t={THEMES.dark} count={20}/>

      {/* Decorative diagonal lines */}
      <div style={{
        position: "absolute", top: 0, left: 0, right: 0, bottom: 0,
        backgroundImage: `repeating-linear-gradient(
          -45deg,
          transparent,
          transparent 80px,
          ${THEMES.dark.oak}06 80px,
          ${THEMES.dark.oak}06 81px
        )`,
        pointerEvents: "none",
      }}/>

      <div style={{ maxWidth: 1200, margin: "0 auto", padding: "0 24px", position: "relative" }}>
        <Reveal>
          <div style={{ textAlign: "center", marginBottom: 80 }}>
            <span style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 12, fontWeight: 600, color: THEMES.dark.gold, letterSpacing: "0.2em", textTransform: "uppercase" }}>Galerie</span>
            <h2 style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: "clamp(32px, 4vw, 52px)", fontWeight: 400, color: THEMES.dark.cream, margin: "16px 0 0" }}>
              Plongez dans notre <GlowText t={THEMES.dark}>univers</GlowText>
            </h2>
            <p style={{
              fontFamily: "'DM Sans', sans-serif", fontSize: 14, color: THEMES.dark.textMuted,
              marginTop: 16, letterSpacing: "0.04em",
            }}>
              Glissez pour explorer
            </p>
          </div>
        </Reveal>
      </div>

      {/* Horizontal draggable track */}
      <div
        ref={trackRef}
        onMouseDown={handleMouseDown}
        onMouseUp={handleMouseUp}
        onMouseLeave={handleMouseUp}
        onMouseMove={handleMouseMove}
        style={{
          display: "flex",
          gap: 40,
          padding: "20px 80px 60px",
          overflowX: "auto",
          cursor: isDragging ? "grabbing" : "grab",
          scrollbarWidth: "none",
          msOverflowStyle: "none",
          justifyContent: "center",
          alignItems: "flex-start",
        }}
        className="gallery-showcase"
      >
        {photos.map((p, i) => (
          <Reveal key={i} delay={i * 0.15}>
            <GalleryCard src={p.src} label={p.label} index={i} t={THEMES.dark} scrollP={scrollP}/>
          </Reveal>
        ))}
      </div>

      {/* Scroll progress bar */}
      <div style={{ maxWidth: 200, margin: "0 auto", height: 2, background: `${THEMES.dark.oak}20`, borderRadius: 1, overflow: "hidden" }}>
        <div style={{
          width: `${Math.min(scrollP * 100, 100)}%`,
          height: "100%",
          background: `linear-gradient(90deg, ${THEMES.dark.gold}, ${THEMES.dark.cognac})`,
          borderRadius: 1,
          transition: "width 0.3s",
          boxShadow: `0 0 10px ${THEMES.dark.ledGlow}`,
        }}/>
      </div>
    </section>
  );
}

// ═══════════════════════════════════════════
// TESTIMONIALS — Infinite marquee with glassmorphism
// ═══════════════════════════════════════════
function TestimonialCard({ review, t, direction }) {
  const [hov, setHov] = useState(false);
  return (
    <div
      onMouseEnter={() => setHov(true)}
      onMouseLeave={() => setHov(false)}
      style={{
        flex: "0 0 380px",
        background: hov
          ? `linear-gradient(135deg, ${t.bgCard}ee, ${t.oak}15)`
          : `${t.bgCard}cc`,
        backdropFilter: "blur(20px) saturate(150%)",
        borderRadius: 28,
        padding: "36px 30px 32px",
        border: `1px solid ${hov ? t.gold + "35" : t.oak + "12"}`,
        position: "relative",
        overflow: "hidden",
        transition: "all 0.5s cubic-bezier(0.22,1,0.36,1)",
        boxShadow: hov
          ? `0 20px 60px ${t.shadow}, 0 0 30px ${t.ledGlow}15, inset 0 1px 0 ${t.gold}15`
          : `0 4px 20px ${t.shadow}`,
        transform: hov ? "translateY(-8px) scale(1.02)" : "translateY(0) scale(1)",
        cursor: "default",
      }}
    >
      {/* Decorative gradient orb */}
      <div style={{
        position: "absolute", top: -30, right: -30,
        width: 120, height: 120, borderRadius: "50%",
        background: `radial-gradient(circle, ${t.gold}15, transparent 70%)`,
        filter: "blur(20px)",
        opacity: hov ? 1 : 0.3,
        transition: "opacity 0.5s",
        pointerEvents: "none",
      }}/>

      {/* Quote mark with LED glow */}
      <div style={{
        fontFamily: "'Cormorant Garamond', serif",
        fontSize: 64, lineHeight: 1,
        position: "absolute", top: 4, right: 24,
        background: `linear-gradient(135deg, ${t.gold}, ${t.cognac})`,
        WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent",
        opacity: hov ? 0.6 : 0.15,
        transition: "opacity 0.5s",
        filter: hov ? `drop-shadow(0 0 12px ${t.ledGlow})` : "none",
      }}>"</div>

      {/* Star rating with staggered animation */}
      <div style={{ display: "flex", gap: 3, marginBottom: 20, position: "relative" }}>
        {Array.from({ length: 5 }, (_, j) => (
          <span key={j} style={{
            color: t.gold,
            filter: hov ? `drop-shadow(0 0 6px ${t.ledGlow}50)` : `drop-shadow(0 0 2px ${t.ledGlow}20)`,
            transition: `all 0.3s ${j * 0.06}s`,
            transform: hov ? "scale(1.15)" : "scale(1)",
          }}>{I.star}</span>
        ))}
      </div>

      {/* Review text */}
      <p style={{
        fontFamily: "'DM Sans', sans-serif",
        fontSize: 15, color: t.textMuted,
        lineHeight: 1.82, margin: "0 0 28px",
        fontStyle: "italic",
        position: "relative",
      }}>
        {review.text}
      </p>

      {/* Divider line */}
      <div style={{
        width: hov ? 60 : 30, height: 1,
        background: `linear-gradient(90deg, ${t.gold}, ${t.cognac})`,
        marginBottom: 20,
        transition: "width 0.5s cubic-bezier(0.22,1,0.36,1)",
        boxShadow: `0 0 8px ${t.ledGlow}30`,
      }}/>

      {/* Author info */}
      <div style={{ display: "flex", alignItems: "center", gap: 14, position: "relative" }}>
        <div style={{
          width: 44, height: 44, borderRadius: "50%",
          background: `linear-gradient(135deg, ${t.cognac}, ${t.gold})`,
          display: "flex", alignItems: "center", justifyContent: "center",
          fontFamily: "'Cormorant Garamond', serif",
          fontSize: 17, fontWeight: 600, color: "#fff",
          boxShadow: `0 0 20px ${t.ledGlow}25`,
          transition: "box-shadow 0.4s",
        }}>
          {review.name[0]}
        </div>
        <div>
          <span style={{
            fontFamily: "'DM Sans', sans-serif",
            fontSize: 14, fontWeight: 600, color: t.text,
            display: "block",
          }}>{review.name}</span>
          <span style={{
            fontFamily: "'DM Sans', sans-serif",
            fontSize: 11, color: t.textLight,
            letterSpacing: "0.05em",
          }}>Cliente fidèle</span>
        </div>
      </div>
    </div>
  );
}

function Testimonials({ t }) {
  const reviews = [
    { name: "Camille L.", text: "Un salon magnifique avec une ambiance incroyable. Le résultat est toujours au-delà de mes attentes. Je recommande les yeux fermés !" },
    { name: "Sophie M.", text: "La déco est sublime et l'accueil chaleureux. Mon balayage est exactement ce que je voulais. Merci pour ce moment de détente." },
    { name: "Juliette R.", text: "Enfin un salon qui prend le temps d'écouter ! Les soins sont exceptionnels et l'espace est pensé dans les moindres détails." },
    { name: "Marie D.", text: "Une expérience unique à chaque visite. L'équipe est aux petits soins et le cadre est absolument magnifique. Mon salon coup de cœur !" },
    { name: "Laura B.", text: "Le meilleur salon de la région, sans hésitation. Professionnalisme, écoute et résultat parfait. Je ne changerais pour rien au monde." },
  ];

  const [activeIndex, setActiveIndex] = useState(0);
  const [isAutoPlay, setIsAutoPlay] = useState(true);

  useEffect(() => {
    if (!isAutoPlay) return;
    const timer = setInterval(() => {
      setActiveIndex(prev => (prev + 1) % reviews.length);
    }, 4000);
    return () => clearInterval(timer);
  }, [isAutoPlay, reviews.length]);

  return (
    <section id="avis" style={{
      padding: "130px 24px",
      background: t.bgAlt,
      position: "relative",
      overflow: "hidden",
    }}>
      {/* Subtle radial gradient background */}
      <div style={{
        position: "absolute",
        top: "50%", left: "50%",
        transform: "translate(-50%, -50%)",
        width: 800, height: 800,
        background: `radial-gradient(circle, ${t.gold}06, transparent 70%)`,
        pointerEvents: "none",
      }}/>

      <div style={{ maxWidth: 1200, margin: "0 auto", position: "relative" }}>
        <Reveal>
          <div style={{ textAlign: "center", marginBottom: 80 }}>
            <span style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 12, fontWeight: 600, color: t.cognac, letterSpacing: "0.2em", textTransform: "uppercase" }}>Témoignages</span>
            <h2 style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: "clamp(32px, 4vw, 52px)", fontWeight: 400, color: t.text, margin: "16px 0 0" }}>
              Ce qu'elles en <GlowText t={t}>disent</GlowText>
            </h2>
          </div>
        </Reveal>

        {/* Featured testimonial — large center card */}
        <Reveal delay={0.1}>
          <div
            onMouseEnter={() => setIsAutoPlay(false)}
            onMouseLeave={() => setIsAutoPlay(true)}
            style={{
              maxWidth: 680,
              margin: "0 auto 60px",
              position: "relative",
              minHeight: 260,
            }}
          >
            {reviews.map((r, i) => (
              <div key={i} style={{
                position: i === activeIndex ? "relative" : "absolute",
                top: 0, left: 0, right: 0,
                opacity: i === activeIndex ? 1 : 0,
                transform: i === activeIndex ? "translateY(0) scale(1)" : "translateY(20px) scale(0.95)",
                transition: "all 0.6s cubic-bezier(0.22,1,0.36,1)",
                pointerEvents: i === activeIndex ? "auto" : "none",
              }}>
                <div style={{
                  background: `${t.bgCard}dd`,
                  backdropFilter: "blur(24px) saturate(160%)",
                  borderRadius: 32,
                  padding: "52px 48px 44px",
                  border: `1px solid ${t.gold}18`,
                  boxShadow: `0 20px 80px ${t.shadow}, 0 0 40px ${t.ledGlow}08, inset 0 1px 0 ${t.gold}10`,
                  textAlign: "center",
                  position: "relative",
                  overflow: "hidden",
                }}>
                  {/* Animated border glow */}
                  <div style={{
                    position: "absolute", inset: 0, borderRadius: 32,
                    background: `conic-gradient(from ${(activeIndex * 72)}deg, transparent, ${t.gold}10, transparent, ${t.cognac}08, transparent)`,
                    pointerEvents: "none",
                  }}/>

                  <div style={{
                    fontFamily: "'Cormorant Garamond', serif",
                    fontSize: 100, lineHeight: 0.8,
                    background: `linear-gradient(135deg, ${t.gold}40, ${t.cognac}20)`,
                    WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent",
                    marginBottom: 8,
                    filter: `drop-shadow(0 0 20px ${t.ledGlow}30)`,
                  }}>"</div>

                  <div style={{ display: "flex", gap: 4, justifyContent: "center", marginBottom: 24 }}>
                    {Array.from({ length: 5 }, (_, j) => (
                      <span key={j} style={{
                        color: t.gold,
                        filter: `drop-shadow(0 0 6px ${t.ledGlow}40)`,
                        fontSize: 16,
                      }}>{I.star}</span>
                    ))}
                  </div>

                  <p style={{
                    fontFamily: "'Cormorant Garamond', serif",
                    fontSize: "clamp(18px, 2.5vw, 24px)",
                    color: t.text,
                    lineHeight: 1.7,
                    fontStyle: "italic",
                    margin: "0 0 32px",
                    fontWeight: 400,
                    position: "relative",
                  }}>
                    {r.text}
                  </p>

                  <div style={{
                    width: 40, height: 1, margin: "0 auto 24px",
                    background: `linear-gradient(90deg, transparent, ${t.gold}, transparent)`,
                    boxShadow: `0 0 10px ${t.ledGlow}20`,
                  }}/>

                  <div style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 14 }}>
                    <div style={{
                      width: 48, height: 48, borderRadius: "50%",
                      background: `linear-gradient(135deg, ${t.cognac}, ${t.gold})`,
                      display: "flex", alignItems: "center", justifyContent: "center",
                      fontFamily: "'Cormorant Garamond', serif",
                      fontSize: 18, fontWeight: 600, color: "#fff",
                      boxShadow: `0 0 25px ${t.ledGlow}30`,
                    }}>{r.name[0]}</div>
                    <div style={{ textAlign: "left" }}>
                      <span style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 15, fontWeight: 600, color: t.text, display: "block" }}>{r.name}</span>
                      <span style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 12, color: t.textLight }}>Cliente fidèle</span>
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </Reveal>

        {/* Navigation dots */}
        <Reveal delay={0.2}>
          <div style={{
            display: "flex", justifyContent: "center", gap: 12, marginBottom: 60,
          }}>
            {reviews.map((_, i) => (
              <button
                key={i}
                onClick={() => { setActiveIndex(i); setIsAutoPlay(false); setTimeout(() => setIsAutoPlay(true), 8000); }}
                style={{
                  width: i === activeIndex ? 32 : 10,
                  height: 10,
                  borderRadius: 5,
                  background: i === activeIndex
                    ? `linear-gradient(90deg, ${t.cognac}, ${t.gold})`
                    : `${t.oak}25`,
                  border: "none",
                  cursor: "pointer",
                  transition: "all 0.4s cubic-bezier(0.22,1,0.36,1)",
                  boxShadow: i === activeIndex ? `0 0 12px ${t.ledGlow}40` : "none",
                }}
              />
            ))}
          </div>
        </Reveal>

        {/* Scrolling marquee row — small preview cards */}
        <div style={{ overflow: "hidden", position: "relative" }}>
          {/* Fade edges */}
          <div style={{ position: "absolute", top: 0, bottom: 0, left: 0, width: 80, background: `linear-gradient(90deg, ${t.bgAlt}, transparent)`, zIndex: 2, pointerEvents: "none" }}/>
          <div style={{ position: "absolute", top: 0, bottom: 0, right: 0, width: 80, background: `linear-gradient(270deg, ${t.bgAlt}, transparent)`, zIndex: 2, pointerEvents: "none" }}/>

          <div style={{
            display: "flex",
            gap: 20,
            animation: "testimonialScroll 25s linear infinite",
            width: "max-content",
          }}>
            {[...reviews, ...reviews, ...reviews].map((r, i) => (
              <div key={i} style={{
                flex: "0 0 auto",
                background: `${t.bgCard}99`,
                backdropFilter: "blur(12px)",
                borderRadius: 16,
                padding: "16px 20px",
                border: `1px solid ${t.oak}10`,
                display: "flex", alignItems: "center", gap: 12,
                minWidth: 260,
              }}>
                <div style={{
                  width: 32, height: 32, borderRadius: "50%",
                  background: `linear-gradient(135deg, ${t.oak}30, ${t.gold}20)`,
                  display: "flex", alignItems: "center", justifyContent: "center",
                  fontFamily: "'Cormorant Garamond', serif", fontSize: 13, fontWeight: 600, color: t.oakDark,
                  flexShrink: 0,
                }}>{r.name[0]}</div>
                <div style={{ overflow: "hidden" }}>
                  <span style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 12, fontWeight: 600, color: t.text, display: "block" }}>{r.name}</span>
                  <span style={{
                    fontFamily: "'DM Sans', sans-serif", fontSize: 11, color: t.textMuted,
                    whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis",
                    display: "block", maxWidth: 180,
                  }}>{r.text}</span>
                </div>
                <div style={{ display: "flex", gap: 1, flexShrink: 0, marginLeft: "auto" }}>
                  {Array.from({ length: 5 }, (_, j) => (
                    <span key={j} style={{ color: t.gold, fontSize: 10 }}>{I.star}</span>
                  ))}
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
}

