function Contact({ t }) {
  const sectionRef = useRef(null);
  const scrollP = useScrollProgress(sectionRef);

  return (
    <section id="contact" ref={sectionRef} style={{
      padding: "130px 24px", position: "relative", overflow: "hidden",
      background: `linear-gradient(170deg, ${t.bgCard} 0%, ${t.bg} 50%, ${t.oak}08 100%)`,
    }}>
      <FloatingParticles t={t} count={12}/>
      <div style={{ maxWidth: 900, margin: "0 auto", textAlign: "center", position: "relative", zIndex: 2 }}>
        <Reveal>
          <div style={{ display: "flex", justifyContent: "center", marginBottom: 48 }}>
            <LEDOvalMirror t={t} size={100} intensity={0.8} showBeam beamProgress={scrollP}>
              <div style={{ color: t.gold, transform: "scale(1.8)", opacity: 0.6 }}>{I.sparkle}</div>
            </LEDOvalMirror>
          </div>
        </Reveal>
        <Reveal delay={0.1}>
          <span style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 12, fontWeight: 600, color: t.cognac, letterSpacing: "0.2em", textTransform: "uppercase" }}>Rendez-vous</span>
          <h2 style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: "clamp(36px, 5vw, 60px)", fontWeight: 400, color: t.text, margin: "16px 0 28px" }}>
            Prête pour votre<br/>
            <GlowText t={t}>transformation</GlowText> ?
          </h2>
        </Reveal>
        <Reveal delay={0.2}>
          <p style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 17, color: t.textMuted, lineHeight: 1.75, maxWidth: 550, margin: "0 auto 48px" }}>
            Réservez votre créneau en un clic ou contactez-nous pour un conseil personnalisé.
          </p>
        </Reveal>
        <Reveal delay={0.3}>
          <Btn t={t} href="tel:+33000000000" primary style={{ boxShadow: `0 8px 40px ${t.cognac}35, 0 0 30px ${t.ledGlow}15` }}>
            {I.phone} Appelez-nous
          </Btn>
        </Reveal>
        <Reveal delay={0.4}>
          <div style={{ display: "flex", justifyContent: "center", gap: 52, marginTop: 72, flexWrap: "wrap" }}>
            {[
              { icon: I.pin, l: "12 rue de la Beauté\n31000 Toulouse" },
              { icon: I.clock, l: "Mar — Sam\n9h00 — 19h00" },
              { icon: I.phone, l: "05 00 00 00 00\ncontact@lhairdutemps.fr" },
            ].map((info, i) => (
              <div key={i} style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 12 }}>
                <div style={{
                  width: 50, height: 50, borderRadius: "50%",
                  background: `${t.oak}10`, display: "flex", alignItems: "center", justifyContent: "center",
                  color: t.cognac, boxShadow: `0 0 20px ${t.ledGlow}15`,
                  border: `1px solid ${t.oak}15`,
                }}>{info.icon}</div>
                <span style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 14, color: t.textMuted, lineHeight: 1.6, textAlign: "center", whiteSpace: "pre-line" }}>{info.l}</span>
              </div>
            ))}
          </div>
        </Reveal>
      </div>
    </section>
  );
}

