// ═══════════════════════════════════════════
// MAIN APP
// ═══════════════════════════════════════════
export default function SalonEclat() {
  const [dark, setDark] = useState(false);
  const t = dark ? THEMES.dark : THEMES.light;

  return (
    <div style={{ background: t.bg, minHeight: "100vh", transition: "background 0.6s ease" }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,400;0,500;0,600;0,700;1,400;1,500&family=DM+Sans:ital,wght@0,300;0,400;0,500;0,600;0,700;1,400&display=swap');
        * { margin: 0; padding: 0; box-sizing: border-box; }
        html { scroll-behavior: smooth; }
        body { overflow-x: hidden; }

        @property --led-angle {
          syntax: '<angle>';
          initial-value: 0deg;
          inherits: false;
        }

        @keyframes ledSpin { to { --led-angle: 360deg; } }
        @keyframes ledPulse {
          0%, 100% { opacity: 0.3; transform: scale(1); }
          50% { opacity: 0.6; transform: scale(1.06); }
        }
        @keyframes ledBreath {
          0%, 100% { opacity: 0.6; box-shadow: 0 0 20px ${t.ledGlow}, 0 0 60px ${t.ledGlow}; }
          50% { opacity: 1; box-shadow: 0 0 35px ${t.ledGlow}, 0 0 90px ${t.ledGlow}; }
        }
        @keyframes scrollPulse {
          0%, 100% { opacity: 0.3; transform: scaleY(1); }
          50% { opacity: 0.9; transform: scaleY(1.4); }
        }
        @keyframes particleFloat {
          0%, 100% { transform: translateY(0) translateX(0); opacity: 0.2; }
          25% { transform: translateY(calc(var(--drift) * -1)) translateX(var(--drift)); opacity: 0.5; }
          50% { transform: translateY(calc(var(--drift) * -0.5)) translateX(calc(var(--drift) * -0.5)); opacity: 0.3; }
          75% { transform: translateY(var(--drift)) translateX(calc(var(--drift) * 0.3)); opacity: 0.45; }
        }
        @keyframes slatGrow {
          from { transform: scaleY(0); opacity: 0; }
          to { transform: scaleY(1); opacity: 1; }
        }
        @keyframes iconSpin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
        @keyframes testimonialScroll {
          0% { transform: translateX(0); }
          100% { transform: translateX(-33.333%); }
        }

        @media (max-width: 768px) {
          .desktop-nav { display: none !important; }
          .mobile-menu-btn { display: block !important; }
          .about-grid { grid-template-columns: 1fr !important; gap: 48px !important; }
          .gallery-showcase { flex-direction: column !important; align-items: center !important; padding: 20px 24px 60px !important; }
          .hero-deco-1, .hero-deco-2, .hero-slats { display: none !important; }
        }
        @media (min-width: 769px) { .mobile-menu-btn { display: none !important; } }
        .gallery-showcase::-webkit-scrollbar { display: none; }

        ::selection { background: ${t.oak}35; color: ${t.text}; }
        @media (prefers-reduced-motion: reduce) {
          *, *::before, *::after { animation-duration: 0.01ms !important; animation-iteration-count: 1 !important; transition-duration: 0.01ms !important; }
        }
      `}</style>

      <CursorGlow t={t}/>
      <ThemeToggle dark={dark} toggle={() => setDark(!dark)} t={t}/>
      <Navbar t={t}/>
      <Hero t={t}/>
      <About t={t}/>
      <Services t={t}/>
      <Gallery t={t}/>
      <Testimonials t={t}/>
      <Contact t={t}/>
      <Footer t={t}/>
    </div>
  );
}
